AN_RED   = colors.HexColor('#C62D33')
AN_GOLD  = colors.HexColor('#B8860B')
AN_DARK  = colors.HexColor('#2C2C2C')
AN_LTRED = colors.HexColor('#FFF5F5')
AN_GREY  = colors.HexColor('#888888')
AN_LGREY = colors.HexColor('#F5F5F5')
AN_WHITE = colors.white

AN_W, AN_H = A4
AN_ML = 10*mm; AN_MR = 10*mm; AN_MT = 8*mm; AN_MB = 10*mm
AN_TW = AN_W - AN_ML - AN_MR

def AN_S(size=10, bold=False, color=colors.black, align=TA_LEFT):
    return ParagraphStyle('ans', fontSize=size,
        fontName='Helvetica-Bold' if bold else 'Helvetica',
        textColor=color, alignment=align, leading=size*1.4,
        spaceAfter=0, spaceBefore=0)

def an_sec_header(num, title):
    label = f"{num}.  {title}" if num else title
    t = Table([[Paragraph(f"<b>{label}</b>", AN_S(10, bold=True, color=AN_WHITE))]], colWidths=[AN_TW])
    t.setStyle(TableStyle([
        ('BACKGROUND',(0,0),(-1,-1),AN_RED),
        ('TOPPADDING',(0,0),(-1,-1),5),('BOTTOMPADDING',(0,0),(-1,-1),5),
        ('LEFTPADDING',(0,0),(-1,-1),8),
    ]))
    return t

def an_empty_section(num, title, msg):
    return KeepTogether([an_sec_header(num, title),
        Table([[Paragraph(msg, AN_S(9, color=AN_GREY))]], colWidths=[AN_TW],
              style=[('LEFTPADDING',(0,0),(-1,-1),8),
                     ('TOPPADDING',(0,0),(-1,-1),4),('BOTTOMPADDING',(0,0),(-1,-1),4)]),
        Spacer(1, 2*mm)])

def an_data_table(headers, rows, col_widths):
    data = [[Paragraph(f"<b>{h}</b>", AN_S(9, bold=True, color=AN_WHITE, align=TA_CENTER)) for h in headers]]
    for row in rows:
        data.append([Paragraph(str(c or ''), AN_S(9, align=TA_CENTER)) for c in row])
    t = Table(data, colWidths=col_widths, repeatRows=1)
    t.setStyle(TableStyle([
        ('BACKGROUND',(0,0),(-1,0),AN_DARK),
        ('ROWBACKGROUNDS',(0,1),(-1,-1),[AN_WHITE,AN_LTRED]),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('TOPPADDING',(0,0),(-1,-1),4),('BOTTOMPADDING',(0,0),(-1,-1),4),
        ('GRID',(0,0),(-1,-1),0.3,colors.HexColor('#DDDDDD')),
    ]))
    return t

def an_date_table(headers, rows, col_widths):
    data = [[Paragraph(f"<b>{h}</b>", AN_S(9, bold=True, color=AN_WHITE, align=TA_CENTER)) for h in headers]]
    keys = [k for k in rows[0].keys() if k not in ('dateFrom','dateTo','date')] if rows else []
    for row in rows:
        d_from = row.get('dateFrom','') or ''
        d_to   = row.get('dateTo','')   or ''
        if not d_from and not d_to:
            single = str(row.get('date','') or '')
            for sep in [' to ',' – ',' - ','–']:
                if sep in single:
                    parts = single.split(sep,1)
                    d_from = parts[0].strip(); d_to = parts[1].strip(); break
            else:
                d_from = single; d_to = ''
        date_text = f"{d_from}<br/>to {d_to}" if d_to else d_from
        date_cell = Paragraph(date_text, AN_S(9, align=TA_CENTER))
        rest = [Paragraph(str(row.get(k,'') or ''), AN_S(9)) for k in keys]
        data.append([date_cell] + rest)
    t = Table(data, colWidths=col_widths, repeatRows=1)
    t.setStyle(TableStyle([
        ('BACKGROUND',(0,0),(-1,0),AN_DARK),
        ('ROWBACKGROUNDS',(0,1),(-1,-1),[AN_WHITE,AN_LTRED]),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('TOPPADDING',(0,0),(-1,-1),4),('BOTTOMPADDING',(0,0),(-1,-1),4),
        ('GRID',(0,0),(-1,-1),0.3,colors.HexColor('#DDDDDD')),
    ]))
    return t

def an_bio_table(rows):
    CW = [38*mm, AN_TW/2-38*mm, 38*mm, AN_TW/2-38*mm]
    data = []; span_cmds = []
    for i, r in enumerate(rows):
        if len(r) == 4:
            data.append([Paragraph(f"<b>{r[0]}</b>", AN_S(10)),
                         Paragraph(str(r[1] or ''), AN_S(10)),
                         Paragraph(f"<b>{r[2]}</b>", AN_S(10)),
                         Paragraph(str(r[3] or ''), AN_S(10))])
        else:
            data.append([Paragraph(f"<b>{r[0]}</b>", AN_S(10)),
                         Paragraph(str(r[1] or ''), AN_S(10)),'',''])
            span_cmds.append(('SPAN',(1,i),(3,i)))
    style_cmds = [
        ('TOPPADDING',(0,0),(-1,-1),3),('BOTTOMPADDING',(0,0),(-1,-1),3),
        ('LEFTPADDING',(0,0),(-1,-1),6),
        ('LINEBELOW',(0,0),(-1,-2),0.3,colors.HexColor('#EEEEEE')),
        ('LINEABOVE',(0,8),(-1,8),1,colors.HexColor('#BBBBBB'),1,(3,3)),
    ] + span_cmds
    for i, r in enumerate(rows):
        style_cmds.append(('BACKGROUND',(0,i),(0,i),AN_LGREY))
        if len(r) == 4: style_cmds.append(('BACKGROUND',(2,i),(2,i),AN_LGREY))
    t = Table(data, colWidths=CW)
    t.setStyle(TableStyle(style_cmds))
    return t

def an_format_position(position, prof_level, specialty):
    pos_map = {"Doctor":"Physician"}
    position   = pos_map.get(str(position or ''), str(position or ''))
    prof_level = str(prof_level or "").replace(" Doctor","").replace("Doctor ","").strip()
    specialty  = str(specialty or "")
    return " — ".join([p for p in [position, prof_level, specialty] if p])

def build_an_pdf(data, redacted=False):
    # Ensure all string fields are actually strings (sheet may send integers)
    for k in ['position','profLevel','specialty','fullName','cnic','passportNo',
              'passportExpiry','dob','gender','nationality','religion','maritalStatus',
              'dependents','height','weight','gccExp','english','availability',
              'email','phone','address','qualLevel','gradCountry']:
        if k in data: data[k] = str(data[k] or '')
    buf = io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            leftMargin=AN_ML, rightMargin=AN_MR,
                            topMargin=AN_MT, bottomMargin=AN_MB)
    story = []
    pos_line = an_format_position(data.get('position',''), data.get('profLevel',''), data.get('specialty',''))

    # Logo
    logo_b64 = data.get('logoBase64','')
    if logo_b64:
        logo_elem = Image(io.BytesIO(base64.b64decode(logo_b64)), width=28*mm, height=28*mm)
    else:
        logo_elem = Table([["AL NAJAM\nLOGO"]], colWidths=[30*mm], rowHeights=[32*mm])
        logo_elem.setStyle(TableStyle([('ALIGN',(0,0),(-1,-1),'CENTER'),('VALIGN',(0,0),(-1,-1),'MIDDLE'),
            ('FONTSIZE',(0,0),(-1,-1),7),('TEXTCOLOR',(0,0),(-1,-1),AN_GREY),
            ('BOX',(0,0),(-1,-1),0.5,colors.HexColor('#CCCCCC')),('BACKGROUND',(0,0),(-1,-1),AN_LGREY)]))

    # Photo
    photo_b64 = data.get('photoBase64','')
    if photo_b64:
        photo_elem = Image(io.BytesIO(base64.b64decode(photo_b64)), width=30*mm, height=38*mm)
    else:
        photo_elem = Table([["PHOTO"]], colWidths=[30*mm], rowHeights=[38*mm])
        photo_elem.setStyle(TableStyle([('ALIGN',(0,0),(-1,-1),'CENTER'),('VALIGN',(0,0),(-1,-1),'MIDDLE'),
            ('FONTSIZE',(0,0),(-1,-1),9),('TEXTCOLOR',(0,0),(-1,-1),AN_GREY),
            ('BOX',(0,0),(-1,-1),0.5,colors.HexColor('#CCCCCC')),('BACKGROUND',(0,0),(-1,-1),AN_LGREY)]))

    title_content = [
        Paragraph("<b>RECRUITMENT APPLICATION FORM</b>", AN_S(15,bold=True,color=AN_RED,align=TA_CENTER)),
        Spacer(1,2*mm),
        Paragraph("Al Najam International — Human Resource Providers Since 1971 | License # 0899/LHR",
                  AN_S(8,color=AN_GOLD,align=TA_CENTER)),
        Spacer(1,3*mm),
        Paragraph(f"<b>Position:</b> {pos_line}", AN_S(10.5,align=TA_CENTER)),
    ]
    hdr = Table([[logo_elem, title_content, photo_elem]], colWidths=[32*mm, AN_TW-64*mm, 32*mm])
    hdr.setStyle(TableStyle([
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),('ALIGN',(0,0),(-1,-1),'CENTER'),
        ('LINEBELOW',(0,0),(-1,-1),2,AN_RED),
        ('TOPPADDING',(0,0),(-1,-1),4),('BOTTOMPADDING',(0,0),(-1,-1),6),
    ]))
    story.append(hdr)
    story.append(Spacer(1,3*mm))

    # Key Skills
    skills = [s for s in (data.get('skills') or []) if s]
    if skills:
        story.append(KeepTogether([
            an_sec_header("","KEY SKILLS"),
            Table([[Paragraph("   •   ".join(skills), AN_S(10))]], colWidths=[AN_TW],
                  style=[('TOPPADDING',(0,0),(-1,-1),5),('BOTTOMPADDING',(0,0),(-1,-1),5),
                         ('LEFTPADDING',(0,0),(-1,-1),8),('BACKGROUND',(0,0),(-1,-1),AN_LGREY)]),
            Spacer(1,2*mm)
        ]))

    # Helper to safely convert to string
    def s(v): return str(v) if v is not None else ''

    # Bio
    bio_rows = [
        ("Full Name:",       s(data.get('fullName','')),       "Date of Birth:",       s(data.get('dob',''))),
        ("CNIC:",            s(data.get('cnic','')),            "Gender:",              s(data.get('gender',''))),
        ("Passport No:",     s(data.get('passportNo','')),      "Nationality:",         s(data.get('nationality',''))),
        ("Passport Expiry:", s(data.get('passportExpiry','')),  "Religion:",            s(data.get('religion',''))),
        ("Marital Status:",  s(data.get('maritalStatus','')),   "Dependents:",          s(data.get('dependents',''))),
        ("Height:",          s(data.get('height','')),          "Weight:",              s(data.get('weight',''))),
        ("GCC Experience:",  s(data.get('gccExp','')),          "English Proficiency:", s(data.get('english',''))),
        ("Availability:",    s(data.get('availability','')),),
    ]
    if not redacted:
        bio_rows.append(("Email:", s(data.get('email','')), "Phone:", s(data.get('phone',''))))
        bio_rows.append(("Address:", s(data.get('address','')),))
    story.append(KeepTogether([an_sec_header("1","BIOGRAPHICAL DATA"), an_bio_table(bio_rows), Spacer(1,2*mm)]))

    # Education
    quals = [q for q in (data.get('qualifications') or []) if q.get('degree') or q.get('institution')]
    if quals:
        rows = [{'dateFrom':q.get('dateFrom',''),'dateTo':q.get('dateTo',''),
                 'degree':q.get('degree',''),'institution':q.get('institution',''),'country':q.get('country','')} for q in quals]
        story.append(KeepTogether([an_sec_header("2","EDUCATION  (most recent first)"),
            an_date_table(["Date","Qualification / Degree","Institution","Country"],rows,[32*mm,58*mm,75*mm,25*mm]),
            Spacer(1,2*mm)]))
    else:
        story.append(an_empty_section("2","EDUCATION  (most recent first)","No education entries provided."))

    # Training
    trains = [t for t in (data.get('training') or []) if t.get('discipline') or t.get('institution')]
    if trains:
        rows = [{'dateFrom':t.get('dateFrom',''),'dateTo':t.get('dateTo',''),
                 'discipline':t.get('discipline',''),'institution':t.get('institution',''),'country':t.get('country','')} for t in trains]
        story.append(KeepTogether([an_sec_header("3","TRAINING / FELLOWSHIP"),
            an_date_table(["Date","Discipline / Specialty","Institution","Country"],rows,[32*mm,58*mm,75*mm,25*mm]),
            Spacer(1,2*mm)]))
    else:
        story.append(an_empty_section("3","TRAINING / FELLOWSHIP","No training entries provided."))

    # Licenses
    lics = [l for l in (data.get('licenses') or []) if l.get('licenseNo') or l.get('authority')]
    if lics:
        lic_rows = [[l.get('licenseNo',''),l.get('designation',''),
                     l.get('issueDate',''),l.get('expiryDate',''),l.get('authority','')] for l in lics]
        story.append(KeepTogether([an_sec_header("4","PROFESSIONAL LICENSES  (most recent first)"),
            an_data_table(["License No","Designation","Issue Date","Expiry","Authority"],
                          lic_rows,[28*mm,38*mm,26*mm,26*mm,72*mm]),
            Spacer(1,2*mm)]))
    else:
        story.append(an_empty_section("4","PROFESSIONAL LICENSES  (most recent first)","No licenses provided."))

    # Experience
    exps = [e for e in (data.get('experience') or []) if e.get('position') or e.get('institution')]
    if exps:
        rows = [{'dateFrom':e.get('dateFrom',''),'dateTo':e.get('dateTo',''),
                 'position':e.get('position',''),'institution':e.get('institution',''),'country':e.get('country','')} for e in exps]
        story.append(KeepTogether([an_sec_header("5","WORK EXPERIENCE  (most recent first)"),
            an_date_table(["Date","Position / Designation","Institution","Country"],rows,[32*mm,58*mm,75*mm,25*mm]),
            Spacer(1,2*mm)]))
    else:
        story.append(an_empty_section("5","WORK EXPERIENCE  (most recent first)","No experience entries provided."))

    # Footer
    story.append(HRFlowable(width=AN_TW, thickness=1, color=AN_GOLD, spaceAfter=2*mm))
    footer_txt = ("Al Najam International  |  License # 0899/LHR  |  Human Resource Providers Since 1971<br/>"
                  "+92 300 4747 115  |  support@alnajam.com  |  www.alnajam.com")
    if redacted:
        footer_txt += "<br/><font color='#C62D33'><b>[REDACTED — Contact details removed]</b></font>"
    story.append(Paragraph(footer_txt, AN_S(8,color=AN_GREY,align=TA_CENTER)))

    doc.build(story)
    buf.seek(0)
    return buf

@app.route('/generate', methods=['POST'])
def generate():
    try:
        data     = request.get_json()
        redacted = data.get('redacted', False)
        pdf_buf  = build_an_pdf(data, redacted)
        suffix   = "Redacted" if redacted else "Full"
        parts    = [str(data.get('position','') or ''), str(data.get('profLevel','') or ''),
                    str(data.get('specialty','') or ''), str(data.get('fullName','') or '')]
        filename = " — ".join([p for p in parts if p]) + f" — {suffix}.pdf"
        return send_file(pdf_buf, mimetype='application/pdf',
                         as_attachment=True, download_name=filename)
    except Exception as e:
        print("GENERATE ERROR:", e)
        import traceback; traceback.print_exc()
        return jsonify({'error': str(e)}), 500


@app.route('/generate_ngha', methods=['POST'])
def generate_ngha():
    """Generate NGHA/CRMS PDF and return bytes directly (no email)"""
    try:
        data = request.get_json()
        pdf  = build_pdf(data)
        name = data.get('candidate_name', 'Candidate').replace(' ', '_')
        return send_file(
            io.BytesIO(pdf),
            mimetype='application/pdf',
            as_attachment=True,
            download_name=f"NGHA_{name}.pdf"
        )
    except Exception as e:
        print("GENERATE_NGHA ERROR:", e)
        import traceback; traceback.print_exc()
        return jsonify({"ok": False, "error": str(e)}), 500

@app.route('/health', methods=['GET'])
def health(): return jsonify({"status": "running", "services": ["cmrs", "alnajam-cv", "ngha"]})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', 5000)))









# ═══════════════════════════════════════════════════════════════════════════
# NGHA ALLIED HEALTH — EXACT REPLICA v7
# ═══════════════════════════════════════════════════════════════════════════

def build_ngha_ah_pdf(data):
    import io, base64
    from datetime import datetime
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.lib.styles import ParagraphStyle
    from reportlab.lib.enums import TA_LEFT, TA_CENTER, TA_RIGHT
    from reportlab.platypus import (SimpleDocTemplate, Table, TableStyle,
                                    Paragraph, Spacer, HRFlowable, PageBreak)
    from reportlab.platypus.flowables import Image as RLImage

    F  = 'Helvetica'
    FB = 'Helvetica-Bold'

    buf = io.BytesIO()
    doc_obj = SimpleDocTemplate(buf, pagesize=A4,
        leftMargin=7.5*mm, rightMargin=7.5*mm,
        topMargin=9.9*mm, bottomMargin=13.4*mm)
    W = 181.0 * mm

    BLK  = colors.black
    WHT  = colors.white
    LGY  = colors.HexColor('#f2f2f2')
    BLGY = colors.HexColor('#cccccc')
    HDR  = colors.HexColor('#595959')

    def ST(sz=9.5, bold=False, align=TA_LEFT, col=BLK):
        return ParagraphStyle('', fontSize=sz, fontName=FB if bold else F,
                              leading=sz*1.4, alignment=align, textColor=col)
    def P(txt, sz=9.5, bold=False, align=TA_LEFT, col=BLK):
        return Paragraph(str(txt or ''), ST(sz, bold, align, col))
    def s(v):
        v = str(v).strip() if v else ''
        return '' if v.lower() in ('none','null','false','') else v
    def chk(label, checked=False):
        return f"{'[X]' if checked else '[ ]'}  {label}"
    def img_b64(b64str, w, h):
        try:
            return RLImage(io.BytesIO(base64.b64decode(b64str)), width=w, height=h)
        except:
            return P('')

    BASE = [
        ('GRID',          (0,0),(-1,-1), 0.5, BLGY),
        ('BOX',           (0,0),(-1,-1), 0.5, BLGY),
        ('TOPPADDING',    (0,0),(-1,-1), 3),
        ('BOTTOMPADDING', (0,0),(-1,-1), 3),
        ('LEFTPADDING',   (0,0),(-1,-1), 4),
        ('RIGHTPADDING',  (0,0),(-1,-1), 4),
        ('VALIGN',        (0,0),(-1,-1), 'MIDDLE'),
        ('FONTNAME',      (0,0),(-1,-1), F),
        ('FONTSIZE',      (0,0),(-1,-1), 9.5),
    ]

    def TS(*extra): return TableStyle(BASE + list(extra))
    def DTS():
        return TableStyle(BASE + [
            ('BACKGROUND',(0,0),(-1,0),HDR),
            ('TEXTCOLOR', (0,0),(-1,0),WHT),
            ('FONTNAME',  (0,0),(-1,0),FB),
            ('ALIGN',     (0,0),(-1,0),'CENTER'),
        ])
    def sec(txt):
        t = Table([[P(f'<b>{txt}</b>',9.5,True)]], colWidths=[W])
        t.setStyle(TableStyle([
            ('BOX',(0,0),(-1,-1),0.5,BLGY),
            ('BACKGROUND',(0,0),(-1,-1),LGY),
            ('TOPPADDING',(0,0),(-1,-1),3),
            ('BOTTOMPADDING',(0,0),(-1,-1),3),
            ('LEFTPADDING',(0,0),(-1,-1),5),
        ]))
        return t

    # ── Data ─────────────────────────────────────────────────────────────
    full_name   = s(data.get('fullName',''))
    position    = s(data.get('position',''))
    specialty   = s(data.get('specialty',''))
    avail       = s(data.get('availability',''))
    gender      = s(data.get('gender',''))
    religion    = s(data.get('religion',''))
    nationality = s(data.get('nationality',''))
    age         = s(data.get('age',''))
    place_birth = s(data.get('placeOfBirth',''))
    height      = s(data.get('height','')).replace(' cm','').replace('cm','').strip()
    weight      = s(data.get('weight','')).replace(' kg','').replace('kg','').strip()
    marital     = s(data.get('maritalStatus',''))
    spouse_king = s(data.get('spouseInKingdom',''))
    iqama       = s(data.get('iqamaNo',''))
    sponsor     = s(data.get('companySponsor',''))
    visa_type   = s(data.get('visaType',''))
    emg_contact = s(data.get('emergencyName',''))
    emg_mobile  = s(data.get('emergencyMobile',''))
    # Candidate contact details
    email       = s(data.get('email',''))
    phone       = s(data.get('phone',''))
    address     = s(data.get('address',''))
    employed    = s(data.get('currentlyEmployed',''))
    date_left   = s(data.get('dateLeft',''))
    app_date    = s(data.get('appDate',''))
    app_sig     = s(data.get('applicantSignature',''))
    locations   = list(data.get('nghaLocations') or [])
    quals       = list(data.get('qualifications') or [])
    lics        = list(data.get('licenses') or [])
    trains      = list(data.get('training') or [])
    exps        = list(data.get('experience') or [])
    refs        = list(data.get('references') or [])
    disc        = list(data.get('disclosure') or [])

    raw_dob = data.get('dob','') or ''
    try:
        dob = datetime.fromisoformat(str(raw_dob).replace('Z','+00:00')).strftime('%d-%m-%Y') if 'T' in str(raw_dob) else s(raw_dob)
    except:
        dob = s(raw_dob)

    name_parts = full_name.split()
    first_name  = name_parts[0] if name_parts else ''
    family_name = name_parts[-1] if len(name_parts) > 1 else ''

    AN_NAME  = "Al Najam International"
    AN_EMAIL = "support@alnajam.com"
    AN_ADDR  = "Office 109, 1st Floor, Al Hafeez Executive,\nAli Zeb Road, Gulberg 3, Lahore, Pakistan"
    AN_PHONE = "+92 300 4747115"

    LL = 29.0*mm; LV = 62.0*mm; RL = 35.0*mm; RV = 55.0*mm
    RH = 7.5*mm  # standard row height

    story = []

    # ═══════════════════════════════════════════════════════════════════════
    # PAGE 1
    # ═══════════════════════════════════════════════════════════════════════

    # Header: left text | NGHA logo | Arabic image
    ngha_logo   = img_b64(NGHA_LOGO_B64,   20*mm, 20*mm)
    ngha_arabic = img_b64(NGHA_ARABIC_B64, 62*mm, 14*mm)

    hdr = Table([[
        [P('Kingdom of Saudi Arabia',9.5), P('Ministry of National Guard of Health Affairs',9.5)],
        ngha_logo,
        ngha_arabic
    ]], colWidths=[W*0.38, W*0.15, W*0.47])
    hdr.setStyle(TableStyle([
        ('ALIGN',(0,0),(0,0),'LEFT'),('ALIGN',(1,0),(1,0),'CENTER'),('ALIGN',(2,0),(2,0),'RIGHT'),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('TOPPADDING',(0,0),(-1,-1),2),('BOTTOMPADDING',(0,0),(-1,-1),4),
    ]))
    story.append(hdr)
    story.append(HRFlowable(width=W, thickness=0.8, color=BLK, spaceAfter=1*mm))
    story.append(P('<b>International Recruitment Application Form</b>',11,True,TA_CENTER))
    story.append(Spacer(1,2*mm))

    # Date + Location | Position + Photo
    loc_tbl = Table([
        [P(chk('Riyadh',  'Riyadh'  in locations),9),
         P(chk('Jeddah',  'Jeddah'  in locations),9),
         P(chk('Madinah', 'Madinah' in locations),9)],
        [P(chk('Al Ahsa', 'Al Ahsa' in locations),9),
         P(chk('Dammam',  'Dammam'  in locations),9),
         P(chk('PHCs',    'PHCs'    in locations),9)],
        [P(chk('No Preference','No Preference' in locations),9), P('',9), P('',9)],
    ], colWidths=[W*0.155,W*0.155,W*0.155])
    loc_tbl.setStyle(TableStyle([
        ('TOPPADDING',(0,0),(-1,-1),2),('BOTTOMPADDING',(0,0),(-1,-1),2),
        ('LEFTPADDING',(0,0),(-1,-1),2),
    ]))

    left_box = Table([
        [P(f'Date of Application :   {app_date or "DD / MM / YYYY"}',9.5)],
        [P('Preferred location for employment',9.5)],
        [loc_tbl],
    ], colWidths=[W*0.48])
    left_box.setStyle(TableStyle([
        ('BOX',(0,0),(-1,-1),0.5,BLGY),
        ('TOPPADDING',(0,0),(-1,-1),3),('BOTTOMPADDING',(0,0),(-1,-1),3),
        ('LEFTPADDING',(0,0),(-1,-1),5),
    ]))

    pos_tbl = Table([
        [P('Position you are applying for :',9), P(position,9)],
        [P('Area of Speciality :',9),             P(specialty,9)],
        [P('Availability :',9),                   P(avail,9)],
        [P('Referred by : (Name & Badge No.)',9),  P('N/A',9)],
    ], colWidths=[W*0.235,W*0.155], rowHeights=[RH]*4)
    pos_tbl.setStyle(TS(('BACKGROUND',(0,0),(0,-1),LGY)))

    photo = Table([[P('Photo',9,align=TA_CENTER,col=colors.grey)]],
                  colWidths=[W*0.11], rowHeights=[30*mm])
    photo.setStyle(TableStyle([
        ('BOX',(0,0),(-1,-1),0.5,BLGY),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),('VALIGN',(0,0),(-1,-1),'MIDDLE'),
    ]))

    right_col = Table([[pos_tbl, photo]], colWidths=[W*0.39,W*0.11])
    right_col.setStyle(TableStyle([('VALIGN',(0,0),(-1,-1),'TOP')]))

    story.append(Table([[left_box, right_col]], colWidths=[W*0.50,W*0.50]))
    story.append(Spacer(1,1.5*mm))

    # Recruitment Source — left box only, no right box
    story.append(Table([
        [P('Recruitment Source :',9.5), P('',9.5)],
        [P(chk('Agency',True),9),       P(chk('Internet',False),9)],
        [P(chk('Local',False),9),       P(chk('Referred',False),9)],
        [P(chk('Rehire',False),9),      P(chk('Other',False),9)],
    ], colWidths=[W*0.22,W*0.18]))
    story[-1].setStyle(TableStyle([
        ('BOX',(0,0),(-1,-1),0.5,BLGY),('SPAN',(0,0),(1,0)),
        ('TOPPADDING',(0,0),(-1,-1),2),('BOTTOMPADDING',(0,0),(-1,-1),2),
        ('LEFTPADDING',(0,0),(-1,-1),5),
        ('FONTNAME',(0,0),(-1,-1),F),('FONTSIZE',(0,0),(-1,-1),9),
    ]))
    story.append(Spacer(1,1.5*mm))

    # Personal Data — candidate's address/phone/email on right
    story.append(sec('Personal Data : (Please print clearly)'))
    pd = Table([
        [P('First Name :',9.5),   P(first_name,9.5),
         P('Permanent Address:',9.5), P(address,8.5)],
        [P('Second Name :',9.5),  P('',9.5), P('',9.5), P('',9.5)],
        [P('Family Name :',9.5),  P(family_name,9.5),
         P('Telephone No. :',9.5), P(phone,9.5)],
        [P('Gender :',9.5),       P(gender,9.5),
         P('Mobile No. :',9.5),   P(phone,9.5)],
        [P('Religion :',9.5),     P(religion,9.5),
         P('Current Address :',9.5),
         P('(No need to fill if same as permanent).',8)],
        [P('Nationality :',9.5),  P(nationality,9.5), P('',9.5), P('',9.5)],
        [P('Date of Birth\n(DD-MM-YYYY) :',9.5), P(dob,9.5),
         P('Age :',9.5), P(age,9.5)],
        [P('Place of Birth :\n(include Country)',9.5), P(place_birth,9.5),
         P('Telephone No./\nMobile No. :',9.5), P(phone,9.5)],
        [P('Height (in cm) :',9.5), P(f'{height} cm' if height else '',9.5),
         P('Weight (in kgs.) :',9.5), P(f'{weight} kg' if weight else '',9.5)],
        [P('Marital Status:',9.5), P(marital,9.5),
         P('Email Address :',9.5), P(email,9.5)],
        [P('Name of spouse:',9.5),
         P('Last name, first name',9.5,col=colors.grey),
         P('',9.5), P('',9.5)],
    ], colWidths=[LL,LV,RL,RV],
       rowHeights=[RH,RH,RH,RH,RH*1.2,RH,RH*1.3,RH*1.3,RH,RH,RH])
    pd.setStyle(TS(
        ('BACKGROUND',(0,0),(0,-1),LGY),
        ('BACKGROUND',(2,0),(2,-1),LGY),
        ('SPAN',(2,0),(3,1)),
        ('SPAN',(2,4),(3,5)),
        ('SPAN',(2,10),(3,10)),
        ('VALIGN',(2,0),(3,1),'TOP'),
        ('VALIGN',(2,4),(3,5),'TOP'),
    ))
    story.append(pd)

    se = Table([
        [P('Is your Spouse living\nin the Kingdom?',9.5),
         P(f"{chk('Yes',spouse_king=='Yes')}   {chk('No',spouse_king=='No')}",9.5),
         P('Company/Sponsor:',9.5), P(sponsor,9.5)],
        [P('Iqama/Residency Permit No.:',9.5), P(iqama,9.5),
         P('Visa Type:',9.5),
         P(f"{chk('Work',visa_type=='Work')}  {chk('Dependent',visa_type=='Dependent')}  {chk('Visit',visa_type=='Visit')}",9.5)],
        [P('Emergency Contact\nPerson :',9.5), P(emg_contact,9.5),
         P('Mobile No. :',9.5), P(emg_mobile,9.5)],
    ], colWidths=[LL,LV,RL,RV],
       rowHeights=[RH*1.3,RH,RH*1.3])
    se.setStyle(TS(
        ('BACKGROUND',(0,0),(0,-1),LGY),
        ('BACKGROUND',(2,0),(2,-1),LGY),
    ))
    story.append(se)
    story.append(Spacer(1,1.5*mm))

    # Qualifications — 4 fixed rows
    story.append(sec('Qualifications : (Please attach copies of all qualifications listed below)'))
    q_rows = [[P('<b>Name of College/University</b>',9,True,TA_CENTER,WHT),
               P('<b>Country</b>',9,True,TA_CENTER,WHT),
               P('<b>Date Attended\nFrom</b>',9,True,TA_CENTER,WHT),
               P('<b>To</b>',9,True,TA_CENTER,WHT),
               P('<b>Qualification\nGained</b>',9,True,TA_CENTER,WHT)]]
    for q in quals[:4]:
        q_rows.append([P(s(q.get('institution','')),9), P(s(q.get('country','')),9),
                       P(s(q.get('dateFrom','')),9), P(s(q.get('dateTo','')),9),
                       P(s(q.get('degree','')),9)])
    while len(q_rows) < 5: q_rows.append([P('')]*5)
    q_tbl = Table(q_rows, colWidths=[73.1*mm,31.8*mm,19.0*mm,19.2*mm,38.9*mm],
                  rowHeights=[10*mm]+[7*mm]*4)
    q_tbl.setStyle(DTS())
    story.append(q_tbl)
    story.append(Spacer(1,1.5*mm))

    # Licensing — 3 fixed rows
    l_rows = [[P('<b>Professional Licensing Body</b>',9,True,TA_CENTER,WHT),
               P('<b>Country</b>',9,True,TA_CENTER,WHT),
               P('<b>License/Registration No.</b>',9,True,TA_CENTER,WHT),
               P('<b>Expiration Date</b>',9,True,TA_CENTER,WHT)]]
    for l in lics[:3]:
        l_rows.append([P(s(l.get('authority','')),9), P(s(l.get('country','')),9),
                       P(s(l.get('licenseNo','')),9), P(s(l.get('expiryDate','')),9)])
    while len(l_rows) < 4: l_rows.append([P('')]*4)
    l_tbl = Table(l_rows, colWidths=[73.3*mm,31.6*mm,37.9*mm,38.2*mm],
                  rowHeights=[8*mm]+[7*mm]*3)
    l_tbl.setStyle(DTS())
    story.append(l_tbl)

    story.append(Spacer(1,2*mm))
    story.append(HRFlowable(width=W,thickness=0.3,color=BLGY))
    story.append(P('Non-Clinical Form   Rev. 12/2023   Ref# APP 1423-02, Appendix D   <b>Page 1 of 2</b>   APP 1427-18, Appendix C   CPRA # 0601-1158',
                   7.5,align=TA_CENTER,col=colors.grey))

    # ═══════════════════════════════════════════════════════════════════════
    # PAGE 2
    # ═══════════════════════════════════════════════════════════════════════
    story.append(PageBreak())

    # Training — 4 fixed rows
    t_rows = [[P('<b>Trainings Attended</b>',9,True,TA_CENTER,WHT),
               P('<b>Date Attended</b>',9,True,TA_CENTER,WHT),
               P('<b>Course Title</b>',9,True,TA_CENTER,WHT)]]
    for t in trains[:4]:
        t_rows.append([P(s(t.get('discipline','')),9),
                       P(s(t.get('dateFrom','')),9),
                       P(s(t.get('courseTitle','')),9)])
    while len(t_rows) < 5: t_rows.append([P('')]*3)
    t_tbl = Table(t_rows, colWidths=[73.3*mm,38.0*mm,69.7*mm],
                  rowHeights=[8*mm]+[7*mm]*4)
    t_tbl.setStyle(DTS())
    story.append(t_tbl)
    story.append(Spacer(1,2*mm))

    # Employment — 5 fixed rows
    story.append(sec('Employment History : (Start from current or most recent employment and attach a detailed CV/resume supporting this)'))
    e_hdr = [
        [P('<b>Hospital/Company/Employer Name & Address\n(Include Country)\n(No. of Hospital beds, if applicable)</b>',8.5,True,TA_CENTER,WHT),
         P('<b>Dates Employed</b>',8.5,True,TA_CENTER,WHT),
         P('<b>Dates Employed</b>',8.5,True,TA_CENTER,WHT),
         P('<b>Last Position\nHeld/Job Title</b>',8.5,True,TA_CENTER,WHT),
         P('<b>Ward/Unit/\nDepartment\n(No. of beds/\nNurse ratio)</b>',8.5,True,TA_CENTER,WHT)],
        [P('',8.5),
         P('<b>From</b>',8.5,True,TA_CENTER,WHT),
         P('<b>To</b>',8.5,True,TA_CENTER,WHT),
         P('',8.5), P('',8.5)],
    ]
    e_data = []
    for e in exps[:5]:
        e_data.append([P(s(e.get('institution','')),9), P(s(e.get('dateFrom','')),9),
                       P(s(e.get('dateTo','')),9), P(s(e.get('position','')),9),
                       P(s(e.get('wardUnit','')),9)])
    while len(e_data) < 5: e_data.append([P('')]*5)
    e_last = [
        [P('<b>Last Date of Employment :</b>',9), P(date_left,9), P('',9), P('',9), P('',9)],
        [P(f"Are you currently employed ?   {chk('Yes',employed=='Yes')}   {chk('No',employed=='No')}",9),
         P('',9), P('',9), P('Date left (last employment) :',9), P(date_left,9)],
    ]
    all_e = e_hdr + e_data + e_last
    n = len(all_e)
    e_tbl = Table(all_e, colWidths=[73.4*mm,15.9*mm,15.9*mm,37.9*mm,38.0*mm],
                  rowHeights=[14*mm,6*mm]+[7*mm]*5+[7*mm,7*mm])
    e_style = DTS()
    e_style._cmds += [
        ('SPAN',(0,0),(0,1)),('SPAN',(1,0),(2,0)),
        ('SPAN',(3,0),(3,1)),('SPAN',(4,0),(4,1)),
        ('SPAN',(0,n-2),(4,n-2)),
        ('SPAN',(0,n-1),(2,n-1)),
        ('BACKGROUND',(0,2),(-1,n-1),WHT),
    ]
    e_tbl.setStyle(e_style)
    story.append(e_tbl)
    story.append(Spacer(1,2*mm))

    # References — 1 referee, 3 rows fixed
    story.append(sec('Work Related Reference who may be contacted :'))
    ref = refs[0] if refs else {}
    rn = s(ref.get('name','')); rt = s(ref.get('jobTitle',''))
    rw = s(ref.get('work','')); re_em = s(ref.get('email',''))
    rc = s(ref.get('consent','')); yes = rc=='Yes'
    ref_rows = [
        [P('<b>Name</b>',9,True,TA_CENTER,WHT),
         P('<b>Position/\nJob Title</b>',9,True,TA_CENTER,WHT),
         P('<b>Contact Information\n(Include country & area codes)</b>',9,True,TA_CENTER,WHT),
         P('',9,True,TA_CENTER,WHT),
         P('<b>Consent to\nContact</b>',9,True,TA_CENTER,WHT)],
        [P(rn,9), P(rt,9), P('Home :',9), P('',9), P(chk('Yes',yes),9)],
        [P('',9),  P('',9),  P('Work :',9), P(rw,9),
         P(chk('No (will not be contacted\nuntil consent is sought)', not yes and rc!=''),9)],
        [P('',9),  P('',9),  P('Email :',9), P(re_em,9), P('',9)],
    ]
    ref_tbl = Table(ref_rows, colWidths=[66.6*mm,35.4*mm,19.4*mm,25.1*mm,34.5*mm],
                    rowHeights=[10*mm,8*mm,10*mm,8*mm])
    ref_style = DTS()
    ref_style._cmds += [
        ('SPAN',(2,0),(3,0)),
        ('SPAN',(0,1),(0,3)),('SPAN',(1,1),(1,3)),
        ('VALIGN',(0,1),(1,3),'MIDDLE'),
        ('BACKGROUND',(0,1),(-1,-1),WHT),
    ]
    ref_tbl.setStyle(ref_style)
    story.append(ref_tbl)
    story.append(Spacer(1,3*mm))

    # Authorization
    story.append(P('<b>Authorization</b>',10,True,TA_CENTER))
    story.append(Spacer(1,2*mm))
    story.append(P(
        "I hereby authorize the Recruitment Services of Ministry of National Guard Health Affairs to request "
        "and obtain details held about me from any organization, in order to exercise due diligence verifying "
        "the documents and details I have submitted to its office in support of my educational qualifications "
        "and experience.\n\nI understand that these organizations can include academic institutions, professional "
        "medical bodies, licensing and registration bodies and my current and previous employers, including "
        "referees.\n\nFurthermore, I declare that all the information that I have given above is correct to the "
        "best of my knowledge. I understand that I could have my contract terminated (or my offer of employment "
        "cancelled); if it is found that I have deliberately given false or misleading information or if my "
        "professional license is revoked during or after the application process.",9.5))
    story.append(Spacer(1,4*mm))

    sig_tbl = Table([[
        P('<b>Signature of Applicant :</b>',9.5),
        P(app_sig,14,col=colors.HexColor('#1a1a8c')),
        P('<b>Date :</b>',9.5), P(app_date,9.5),
    ]], colWidths=[W*0.30,W*0.22,W*0.12,W*0.36])
    sig_tbl.setStyle(TableStyle([
        ('LINEBELOW',(1,0),(1,0),0.5,BLK),
        ('LINEBELOW',(3,0),(3,0),0.5,BLK),
        ('TOPPADDING',(0,0),(-1,-1),6),('BOTTOMPADDING',(0,0),(-1,-1),6),
    ]))
    story.append(sig_tbl)
    story.append(Spacer(1,2*mm))
    story.append(P("As an essential function and responsibility of a recruitment agency, I confirm that primary "
                   "source verification of the above applicant's license, qualification & experience will be "
                   "implemented when offer released.",9.5))
    story.append(Spacer(1,3*mm))

    # Agency info
    agency = Table([
        [P('<b>Recruitment Agency Information : (If applicable)</b>',9.5,True),'','',''],
        [P('Name of Recruitment Agency :',9.5), P(AN_NAME,9.5),'',''],
        [P('Recruiter Name :',9.5), P(AN_NAME,9.5), P('Email :',9.5), P(AN_EMAIL,9.5)],
        [P('Agency Signature :',9.5), img_b64(SIGN_B64,30*mm,12*mm),
         P('Date :',9.5), P(app_date,9.5)],
    ], colWidths=[LL,LV,RL,RV])
    agency.setStyle(TS(
        ('SPAN',(0,0),(3,0)),('SPAN',(1,1),(3,1)),
        ('BACKGROUND',(0,0),(-1,0),LGY),
        ('BACKGROUND',(0,1),(0,-1),LGY),
        ('BACKGROUND',(2,2),(2,-1),LGY),
        ('FONTNAME',(0,0),(-1,0),FB),
    ))
    story.append(agency)
    story.append(Spacer(1,2*mm))
    story.append(P('<b>THANK YOU FOR TAKING THE TIME TO COMPLETE THIS APPLICATION FORM. PLEASE NOTE THAT APPLICATIONS EXPIRE AFTER ONE YEAR.</b>',
                   9,True,TA_CENTER))
    story.append(Spacer(1,2*mm))
    story.append(HRFlowable(width=W,thickness=0.3,color=BLGY))
    story.append(P('Non-Clinical Form   Rev. 12/2023   Ref# APP 1423-02, Appendix D   <b>Page 2 of 2</b>   APP 1427-18, Appendix C   CPRA # 0601-1158',
                   7.5,align=TA_CENTER,col=colors.grey))

    # ═══════════════════════════════════════════════════════════════════════
    # PAGE 3 — DISCLOSURE
    # ═══════════════════════════════════════════════════════════════════════
    story.append(PageBreak())

    story.append(hdr)
    story.append(HRFlowable(width=W,thickness=0.8,color=BLK,spaceAfter=2*mm))
    story.append(Spacer(1,2*mm))
    story.append(P('<b>Disclosure Form For New Applicants</b>',13,True,TA_CENTER))
    story.append(Spacer(1,3*mm))

    def grey_hdr(txt):
        t = Table([[P(txt,9.5,True,TA_CENTER)]], colWidths=[W])
        t.setStyle(TableStyle([
            ('BOX',(0,0),(-1,-1),0.5,BLGY),
            ('BACKGROUND',(0,0),(-1,-1),LGY),
            ('TOPPADDING',(0,0),(-1,-1),3),('BOTTOMPADDING',(0,0),(-1,-1),3),
            ('FONTNAME',(0,0),(-1,-1),FB),
        ]))
        return t

    story.append(grey_hdr('<b>Part I</b> - To be completed by the Applicant'))
    story.append(Spacer(1,3*mm))

    # Part I — candidate's details
    di = Table([
        [P('Position Applied For :',9.5), P(position,9.5), P('',9.5), P('',9.5)],
        [P('Name',9.5), P(f':  {full_name}',9.5),
         P('Gender:',9.5),
         P(f"{chk('Male',gender=='Male')}   {chk('Female',gender=='Female')}",9.5)],
        [P('Nationality',9.5), P(f':  {nationality}',9.5), P('',9.5), P('',9.5)],
        [P('Postal Address',9.5), P(f':  {address}',9.5), P('',9.5), P('',9.5)],
        [P('Phone No. Including\nCountry Code :',9.5), P(phone,9.5),
         P('Email:',9.5), P(email,9.5)],
    ], colWidths=[LL,LV,RL,RV],
       rowHeights=[7*mm,7*mm,7*mm,10*mm,8*mm])
    di.setStyle(TS(
        ('BACKGROUND',(0,0),(0,-1),LGY),
        ('SPAN',(0,0),(3,0)),
        ('SPAN',(1,2),(3,2)),
        ('SPAN',(1,3),(3,3)),
        ('BACKGROUND',(2,1),(2,1),LGY),
        ('BACKGROUND',(2,4),(2,4),LGY),
        ('VALIGN',(1,3),(1,3),'TOP'),
    ))
    story.append(di)
    story.append(Spacer(1,3*mm))
    story.append(P("I disclose herewith all my relationships and affiliations with those currently employed in all National Guard Health Affairs facilities*.",9.5))
    story.append(Spacer(1,3*mm))
    story.append(P('<b>Relatives / Acquaintances working for National Guard Health Affairs:</b>',9.5,True))
    story.append(Spacer(1,2*mm))

    # Disclosure table — 5 fixed rows
    d_rows = [[P('',9),
               P('<b>Name</b>',9,True,TA_CENTER,WHT),
               P('<b>Position</b>',9,True,TA_CENTER,WHT),
               P('<b>Department</b>',9,True,TA_CENTER,WHT),
               P('<b>Relationship To Applicant</b>',9,True,TA_CENTER,WHT)]]
    for i in range(5):
        d = (disc[i] if i < len(disc) else {}) or {}
        d_rows.append([P(str(i+1),9,align=TA_CENTER),
                       P(s(d.get('name','')),9), P(s(d.get('position','')),9),
                       P(s(d.get('department','')),9), P(s(d.get('relationship','')),9)])
    d_tbl = Table(d_rows, colWidths=[6.7*mm,47.2*mm,50.8*mm,38.0*mm,38.3*mm],
                  rowHeights=[8*mm]+[7*mm]*5)
    d_tbl.setStyle(DTS())
    story.append(d_tbl)
    story.append(Spacer(1,4*mm))
    story.append(P("I hereby certify that the above information is true and complete to the best of my knowledge and belief.",9.5))
    story.append(Spacer(1,8*mm))

    cert = Table([
        [P('',9.5), P('',9.5), P('N/A',9.5,align=TA_CENTER), P(app_date,9.5,align=TA_CENTER)],
        [P('',9.5), P('<b>Name & Signature</b>',9.5,True,TA_CENTER),
         P('<b>Date</b>',9.5,True,TA_CENTER), P('',9.5)],
    ], colWidths=[W*0.08,W*0.45,W*0.22,W*0.25])
    cert.setStyle(TableStyle([
        ('LINEABOVE',(1,0),(1,0),0.5,BLK),('LINEABOVE',(2,0),(2,0),0.5,BLK),
        ('TOPPADDING',(0,0),(-1,-1),3),('BOTTOMPADDING',(0,0),(-1,-1),2),
    ]))
    story.append(cert)
    story.append(Spacer(1,2*mm))
    story.append(P('* <b>Note:</b>  Non-disclosure may result in rejection of application.',9.5))
    story.append(Spacer(1,5*mm))
    story.append(HRFlowable(width=W,thickness=0.5,color=BLGY,spaceAfter=2*mm))

    # Part II — Al Najam
    story.append(grey_hdr('<b>Part II</b> - To be completed by the Agency or appropriate Recruitment Services'))
    story.append(Spacer(1,4*mm))
    story.append(P('<b>Verified By:</b>',9.5,True))
    story.append(Spacer(1,3*mm))

    stamp_box = Table([[img_b64(STAMP_B64,38*mm,38*mm)],
                       [P('Recruitment Stamp',9,align=TA_CENTER,col=colors.grey)]],
                      colWidths=[42*mm])
    stamp_box.setStyle(TableStyle([
        ('BOX',(0,0),(0,0),0.5,BLGY),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('TOPPADDING',(0,0),(-1,-1),3),('BOTTOMPADDING',(0,0),(-1,-1),3),
    ]))

    ver = Table([
        [P('',9.5), P('',9.5), P(AN_NAME,9,align=TA_CENTER), P(app_date,9,align=TA_CENTER)],
        [P('',9.5), P('<b>Name & Signature</b>',9,True,TA_CENTER),
         P('<b>Badge/ID No.</b>',9,True,TA_CENTER),
         P('<b>Date</b>',9,True,TA_CENTER)],
    ], colWidths=[W*0.05,W*0.42,W*0.18,W*0.12])
    ver.setStyle(TableStyle([
        ('LINEABOVE',(1,0),(1,0),0.5,BLK),('LINEABOVE',(2,0),(2,0),0.5,BLK),
        ('LINEABOVE',(3,0),(3,0),0.5,BLK),
        ('TOPPADDING',(0,0),(-1,-1),3),('BOTTOMPADDING',(0,0),(-1,-1),2),
    ]))

    story.append(Table([[stamp_box, ver]], colWidths=[42*mm,W-42*mm]))
    story.append(Spacer(1,3*mm))
    story.append(HRFlowable(width=W,thickness=0.3,color=BLGY))
    story.append(P('Non-Clinical Form   Rev. 04/2014   Ref# APP 1422-08, Appendix B   <b>Page 1 of 1</b>   APP 1427-18, Appendix A   O&M # 0503-0140',
                   7.5,align=TA_CENTER,col=colors.grey))

    doc_obj.build(story)
    buf.seek(0)
    return buf


@app.route('/generate_ngha_ah', methods=['POST'])
def generate_ngha_ah():
    try:
        data = request.get_json()
        pdf_buf = build_ngha_ah_pdf(data)
        pos  = str(data.get('position','') or '')
        name = str(data.get('fullName','') or '')
        fname = "NGHA Allied Health Form — " + " — ".join([p for p in [pos,name] if p]) + ".pdf"
        return send_file(pdf_buf, mimetype='application/pdf',
                         as_attachment=True, download_name=fname)
    except Exception as e:
        print("NGHA AH ERROR:", e)
        import traceback; traceback.print_exc()
        return jsonify({'error': str(e)}), 500
